import json
from decimal import Decimal

class DecimalEncoder(json.JSONEncoder):
    def default(self, o):
        if isinstance(o, Decimal):
            return str(o)
        return super().default(o)

print(json.dumps({'monto': Decimal('10.50')}, cls=DecimalEncoder))

def reconcile(n_in, n_clean, n_quar):
    ok = n_in == n_clean + n_quar
    return {"ok": ok, "n_in": n_in, "n_clean": n_clean, "n_quarantine": n_quar}

print(reconcile(10, 8, 2))
print(reconcile(10, 7, 2))

def publish(n_in, n_clean, n_quar):
    if n_in != n_clean + n_quar:
        raise SystemExit(1)
    return 'published'

print(publish(5, 4, 1))
try:
    publish(5, 4, 0)
except SystemExit:
    print('fail_closed exit non-zero')

